settings.custom_liquid:
{%- liquid

assign show_3x2 = false

assign show_2x3 = false

assign target_collection = null

assign open_new_tab = true

if collection

assign target_collection = collection

endif

if target_collection

if target_collection.metafields.custom.activo_oferta_3x2 and target_collection.metafields.custom.activo_oferta_3x2.value

assign show_3x2 = true

endif

if target_collection.metafields.custom.activo_oferta_2x3 and target_collection.metafields.custom.activo_oferta_2x3.value

assign show_2x3 = true

endif

else

if product.collections and product.collections.size > 0

for c in product.collections

if c.metafields.custom.activo_oferta_3x2 and c.metafields.custom.activo_oferta_3x2.value

assign show_3x2 = true

endif

if c.metafields.custom.activo_oferta_2x3 and c.metafields.custom.activo_oferta_2x3.value

assign show_2x3 = true

endif

if show_3x2 and show_2x3

break

endif

endfor

endif

endif

-%}

{%- if show_3x2 -%}

{%- liquid

assign uid_3x2 = block.id | default: section.id | default: 'promo'

assign image_url_3x2 = ' https://cdn.shopify.com/s/files/1/0569/8797/5773/files/etiqueta_productos_300px-01_aa48952f-ad63-4086-930d-6c11621e9b7b.jpg?v=1762956718 '

assign link_url_3x2  = 'https://www.nqlnstore.com/collections/3x2 '

assign alt_text_3x2  = 'Promoción 3x2'

-%}

<div id="promo-3x2-{{ uid_3x2 }}" class="promo-thin">

{% if link_url_3x2 != blank %}

<a href="{{ link_url_3x2 | escape }}" class="promo-thin__link" rel="noopener" {% if open_new_tab %}target="_blank"{% endif %}>

{% endif %}

<img

src="{{ image_url_3x2 | append: '&width=700' }}"

srcset="{{ image_url_3x2 | append: '&width=350' }} 350w, {{ image_url_3x2 | append: '&width=700' }} 700w"

sizes="350px"

alt="{{ alt_text_3x2 | escape }}"

class="promo-thin__image"

width="350" height="100"

loading="lazy" decoding="async">

{% if link_url_3x2 != blank %}</a>{% endif %}

</div>

<style>
  #promo-3x2-{{ uid_3x2 }}.promo-thin {
    width: 350px;
    height: 100px;
    max-width: 100%;
    margin: 20px 0;
    overflow: hidden;
    border-radius: 15px;
  }
  #promo-3x2-{{ uid_3x2 }} .promo-thin__link {
    display: block;
    width: 100%;
    height: 100%;
    text-decoration: none;
  }
  #promo-3x2-{{ uid_3x2 }} .promo-thin__image {
    display: block;
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 200ms ease;
    transform-origin: center;
  }
  #promo-3x2-{{ uid_3x2 }}:hover .promo-thin__image { transform: scale(1.03); }
</style>
<style>
  #promo-2x3-{{ uid_2x3 }}.promo-thin {
    width: 350px;
    height: 100px;
    max-width: 100%;
    margin: 20px 0;
    overflow: hidden;
    border-radius: 15px;
  }
