{% if product.metafields.custom.mostrar_boton_mayor == true %}
<div class="t4s-liquid_custom_liquid_EEy7z4 t4s-pr__custom-liquid t4s-rte" style="text-align: center;">

  <style>
    .boton-comprar {
      display: inline-block;
      width: 100%;
      max-width: 500px;
      padding: 12px;
      background-color: #001F32;
      color: white;
      border: none;
      border-radius: 100px;
      font-size: 16px;
      cursor: pointer;
      transition: background-color 0.3s ease;
    }

    .boton-comprar:hover {
      background-color: #AD2221;
    }
  </style>

  <a href="https://www.casavauli.com/pages/al-mayor-vauli"
     target="_blank"
     rel="noopener"
     style="text-decoration: none;">
    <button class="boton-comprar">Cotizar al Mayor</button>
  </a>

  <p style="color: #666666; margin-top: 10px; font-size: 14px;">Usted será redirigido a un formulario para la cotización de nuestros productos</p>

  <style>
    .t4s-quantity-wrapper.t4s-sticky-atc__qty {
      display: none;
    }
  </style>

</div>
{% endif %}
